+                   ".*offset units must fit in u4.*") {
+  const uintx offset_units = (uintx)UINT32_MAX + 1;
+  const uintx offset_bytes = offset_units << ArchiveUtils::OFFSET_SHIFT;
+  ArchiveBuilder::to_offset_u4(offset_bytes);
+}
+#endif // ASSERT

